-- ============================================================================
-- FOUNDATION PATH: Present Perfect Tense (COMPLETE)
-- Topic ID: present-perfect
-- Level: intermediate (A2)
-- Total: 120 questions covering ALL 5 subtopics
-- ============================================================================
-- Subtopics covered:
--   1. has/have + V3 (basic structure) - 24 questions
--   2. Regular & Irregular V3 (past participle forms) - 24 questions
--   3. ever, never, already, yet (time markers) - 24 questions
--   4. since vs for (duration) - 24 questions
--   5. Perfect vs Simple Past (when to use each) - 24 questions
-- Distribution: 48 easy, 48 medium, 24 hard per 120 questions
-- ============================================================================

INSERT INTO english_questions (path_id, topic_id, level, question, options, correct_answer, explanation, difficulty) VALUES

-- ============================================================================
-- SUBTOPIC 1: has/have + V3 (basic structure) - 24 questions
-- ============================================================================

-- EASY (10 questions)
('foundation', 'present-perfect', 'intermediate', 'I _____ finished my homework.', '["has", "have", "had", "having"]', 1, 'has/have + V3: I/You/We/They + have + V3. Use "have" with I. Present perfect connects past action to present result.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'She _____ visited Mumbai.', '["has", "have", "had", "having"]', 0, 'has/have + V3: He/She/It + has + V3. Use "has" with she. Past action with present relevance.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'They _____ completed the project.', '["has", "have", "had", "having"]', 1, 'has/have + V3: They + have + V3. Use "have" with they. Completed past action affecting present.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'He _____ eaten lunch.', '["has", "have", "had", "having"]', 0, 'has/have + V3: He + has + V3. Use "has" with he. Past action (eating) with present result (not hungry).', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'We _____ seen this movie.', '["has", "have", "had", "having"]', 1, 'has/have + V3: We + have + V3. Use "have" with we. Past experience relevant now.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'I _____ been to Delhi.', '["has", "have", "had", "having"]', 1, 'has/have + V3: I + have + been. "Been" = past participle of "be". Past experience of visiting.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'She _____ lost her keys.', '["has", "have", "had", "having"]', 0, 'has/have + V3: She + has + lost. Past action (losing) with present result (still doesn''t have them).', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'You _____ done well.', '["has", "have", "had", "having"]', 1, 'has/have + V3: You + have + done. Use "have" with you (always "have", never "has").', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'It _____ stopped raining.', '["has", "have", "had", "having"]', 0, 'has/have + V3: It + has + stopped. Use "has" with it. Past action (stopping) with present result (dry now).', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'My parents _____ arrived.', '["has", "have", "had", "having"]', 1, 'has/have + V3: Plural noun + have + V3. Parents = two people = "have". They arrived and are here now.', 'easy'),

-- MEDIUM (10 questions)
('foundation', 'present-perfect', 'intermediate', 'What is wrong? "I has finished my work."', '["Use have instead of has", "Use had instead of has", "Use having instead of has", "Nothing wrong"]', 0, 'has/have + V3: I = have (not has). Correct: "I have finished my work." Only he/she/it use "has".', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Choose the correct sentence:', '["She have graduated from college.", "She has graduated from college.", "She had graduated from college.", "She having graduated from college."]', 1, 'has/have + V3: She + has + V3. Correct: "She has graduated." Past action (graduation) with present relevance (she''s a graduate now).', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Arrange correctly: homework / finished / I / my / have', '["I have finished my homework", "I finished have my homework", "Have I finished my homework", "I have my homework finished"]', 0, 'has/have + V3: Subject + have/has + V3 + object. Order: I have finished my homework. Statement (not question).', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'What is the error? "They has completed the task."', '["Use have instead of has", "Use had instead of has", "Use having instead of has", "Nothing wrong"]', 0, 'has/have + V3: They = have (not has). Correct: "They have completed the task." I/you/we/they = always "have".', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Telling your boss about completed work:', '["I finish the report.", "I finished the report.", "I have finished the report.", "I am finishing the report."]', 2, 'has/have + V3: Use present perfect to report completed work with current relevance. "I have finished" = it''s done and ready now.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Rearrange: to / She / India / been / has / three / times', '["She has been to India three times", "She been has to India three times", "Has she been to India three times", "She has to India been three times"]', 0, 'has/have + V3: She + has + been + to + place + frequency. Order: She has been to India three times. Past experiences.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Choose the natural sentence:', '["He has ate breakfast.", "He has eaten breakfast.", "He have eaten breakfast.", "He had eaten breakfast."]', 1, 'has/have + V3: He + has + eaten (V3 of eat). Correct: "He has eaten breakfast." Past action, present result (not hungry).', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'What is wrong? "We have finish our lunch."', '["Use finished instead of finish", "Use finishes instead of finish", "Use finishing instead of finish", "Nothing wrong"]', 0, 'has/have + V3: After have/has, need V3 (not base form). Correct: "We have finished our lunch." Must use past participle.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'At a job interview, talking about your experience:', '["I work in IT for 5 years.", "I worked in IT for 5 years.", "I have worked in IT for 5 years.", "I am working in IT for 5 years."]', 2, 'has/have + V3: Ongoing experience from past to present = present perfect. "I have worked for 5 years" = started in past, still relevant/continuing.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Rearrange: keys / lost / has / She / her', '["She has lost her keys", "She lost has her keys", "Has she lost her keys", "She her keys has lost"]', 0, 'has/have + V3: She + has + lost + object. Order: She has lost her keys. Past action, present consequence (can''t find them).', 'medium'),

-- HARD (4 questions)
('foundation', 'present-perfect', 'intermediate', 'Which is correct in formal business email?', '["We received your application.", "We have received your application.", "We are receiving your application.", "We had received your application."]', 1, 'has/have + V3: Present perfect is polite/formal for recent actions. "We have received" = we got it and are processing now. More formal than simple past.', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'Find the error: "Each student have submitted their assignment."', '["Use has instead of have", "Use had instead of have", "Use having instead of have", "No error"]', 0, 'has/have + V3: "Each student" = singular = has. Correct: "Each student has submitted." "Each" = singular subject.', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'Arrange correctly: experience / years / He / of / teaching / has / ten', '["He has ten years of teaching experience", "He has teaching ten years of experience", "Ten years he has of teaching experience", "He ten years has of teaching experience"]', 0, 'has/have + V3: He + has + quantity + of + type. Order: He has ten years of teaching experience. Professional experience statement.', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'What is wrong? "The team have made significant progress."', '["Use has (team = singular)", "Use had instead of have", "Use making instead of made", "Nothing wrong"]', 0, 'has/have + V3: "Team" = collective noun = singular = has. Correct: "The team has made progress." One team = singular.', 'hard'),

-- ============================================================================
-- SUBTOPIC 2: Regular & Irregular V3 (past participle forms) - 24 questions
-- ============================================================================

-- EASY (10 questions)
('foundation', 'present-perfect', 'intermediate', 'I have _____ my homework. (finish - regular)', '["finish", "finished", "finishing", "finishes"]', 1, 'Regular V3: Most verbs add -ed. Finish → finished. Same as past simple for regular verbs.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'She has _____ three languages. (learn - regular)', '["learn", "learned", "learning", "learns"]', 1, 'Regular V3: Learn + ed = learned. Regular past participle = base + ed.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'They have _____ to Mumbai. (go - irregular)', '["go", "went", "gone", "going"]', 2, 'Irregular V3: Go → went (V2) → gone (V3). Present perfect needs V3 "gone" (not "went").', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'He has _____ all the cake. (eat - irregular)', '["eat", "ate", "eaten", "eating"]', 2, 'Irregular V3: Eat → ate (V2) → eaten (V3). Use "eaten" in present perfect (not "ate").', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'We have _____ this movie. (see - irregular)', '["see", "saw", "seen", "seeing"]', 2, 'Irregular V3: See → saw (V2) → seen (V3). Present perfect uses "seen" (not "saw").', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'I have _____ him before. (meet - irregular)', '["meet", "met", "met", "meeting"]', 1, 'Irregular V3: Meet → met (V2) → met (V3). V2 and V3 are the same! Use "met".', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'She has _____ a new car. (buy - irregular)', '["buy", "bought", "bought", "buying"]', 1, 'Irregular V3: Buy → bought (V2) → bought (V3). V2 and V3 are the same! Use "bought".', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'They have _____ the news. (hear - irregular)', '["hear", "heard", "heard", "hearing"]', 1, 'Irregular V3: Hear → heard (V2) → heard (V3). V2 and V3 identical. Use "heard".', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'He has _____ a letter. (write - irregular)', '["write", "wrote", "written", "writing"]', 2, 'Irregular V3: Write → wrote (V2) → written (V3). Present perfect uses "written" (not "wrote").', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'I have _____ my keys. (lose - irregular)', '["lose", "lost", "lost", "losing"]', 1, 'Irregular V3: Lose → lost (V2) → lost (V3). V2 and V3 same. Use "lost".', 'easy'),

-- MEDIUM (10 questions)
('foundation', 'present-perfect', 'intermediate', 'What is wrong? "She has went to the market."', '["Use gone instead of went", "Use go instead of went", "Use going instead of went", "Nothing wrong"]', 0, 'Irregular V3: Go → went (V2) → gone (V3). Correct: "She has gone to the market." Present perfect needs V3 "gone".', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Choose the correct form:', '["I have saw the Taj Mahal.", "I have seen the Taj Mahal.", "I has seen the Taj Mahal.", "I have see the Taj Mahal."]', 1, 'Irregular V3: See → seen. Correct: "I have seen." Must use V3 after have/has.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'What is the error? "They have ate all the food."', '["Use eaten instead of ate", "Use eat instead of ate", "Use eating instead of ate", "Nothing wrong"]', 0, 'Irregular V3: Eat → ate (V2) → eaten (V3). Correct: "They have eaten." Present perfect needs V3.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Complete: He has _____ English for 5 years. (teach - irregular)', '["teach", "taught", "taught", "teaching"]', 1, 'Irregular V3: Teach → taught (V2) → taught (V3). V2 and V3 same. Use "taught".', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Rearrange: book / read / have / I / this', '["I have read this book", "I have readed this book", "I read have this book", "I have this book read"]', 0, 'Irregular V3: Read → read (V2) → read (V3). Same spelling, different pronunciation! Correct: "I have read this book."', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Choose the correct sentence:', '["She has broke the glass.", "She has broken the glass.", "She has breaked the glass.", "She have broken the glass."]', 1, 'Irregular V3: Break → broke (V2) → broken (V3). Correct: "She has broken." Use V3 "broken".', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'What is wrong? "We have spoke to the manager."', '["Use spoken instead of spoke", "Use speak instead of spoke", "Use speaking instead of spoke", "Nothing wrong"]', 0, 'Irregular V3: Speak → spoke (V2) → spoken (V3). Correct: "We have spoken." Must use V3 after have.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Complete: They have _____ the truth. (know - irregular)', '["know", "knew", "known", "knowing"]', 2, 'Irregular V3: Know → knew (V2) → known (V3). Present perfect uses "known" (not "knew").', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Choose the natural sentence:', '["I have drank too much coffee.", "I have drunk too much coffee.", "I have drinked too much coffee.", "I has drunk too much coffee."]', 1, 'Irregular V3: Drink → drank (V2) → drunk (V3). Correct: "I have drunk." Use V3 "drunk".', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'What is the error? "He has began the meeting."', '["Use begun instead of began", "Use begin instead of began", "Use beginning instead of began", "Nothing wrong"]', 0, 'Irregular V3: Begin → began (V2) → begun (V3). Correct: "He has begun." Present perfect needs V3.', 'medium'),

-- HARD (4 questions)
('foundation', 'present-perfect', 'intermediate', 'Find the error: "The movie has just began."', '["Use begun instead of began", "Use begin instead of began", "Use beginning instead of began", "No error"]', 0, 'Irregular V3: Begin → began (V2) → begun (V3). Correct: "The movie has just begun." Must use V3 "begun".', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'Which is grammatically perfect?', '["She has sang the song beautifully.", "She has sung the song beautifully.", "She has singed the song beautifully.", "She have sung the song beautifully."]', 1, 'Irregular V3: Sing → sang (V2) → sung (V3). Correct: "She has sung." Use V3 "sung".', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'What is wrong? "I have swam in this pool before."', '["Use swum instead of swam", "Use swim instead of swam", "Use swimming instead of swam", "Nothing wrong"]', 0, 'Irregular V3: Swim → swam (V2) → swum (V3). Correct: "I have swum." Present perfect needs V3 "swum".', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'Choose the correct form:', '["The bell has rang.", "The bell has rung.", "The bell has ringed.", "The bell have rung."]', 1, 'Irregular V3: Ring → rang (V2) → rung (V3). Correct: "The bell has rung." Use V3 "rung".', 'hard'),

-- ============================================================================
-- SUBTOPIC 3: ever, never, already, yet (time markers) - 24 questions
-- ============================================================================

-- EASY (10 questions)
('foundation', 'present-perfect', 'intermediate', 'Have you _____ been to Delhi?', '["ever", "never", "already", "yet"]', 0, 'ever/never/already/yet: "Ever" = at any time. Use in questions: "Have you ever...?" Asks about lifetime experience.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'I have _____ seen this movie.', '["ever", "never", "already", "yet"]', 1, 'ever/never/already/yet: "Never" = not at any time. Use in statements: "I have never..." Means no experience in your life.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'She has _____ finished her homework.', '["ever", "never", "already", "yet"]', 2, 'ever/never/already/yet: "Already" = sooner than expected. "She has already finished" = she finished earlier than you thought.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'Have you finished your work _____?', '["ever", "never", "already", "yet"]', 3, 'ever/never/already/yet: "Yet" = until now. Use in questions and negatives: "Have you finished yet?" = asking if finished by now.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'I haven''t eaten lunch _____.', '["ever", "never", "already", "yet"]', 3, 'ever/never/already/yet: "Yet" with negatives = haven''t...yet. "I haven''t eaten yet" = still haven''t eaten (but will).', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'Have you _____ tried Indian food?', '["ever", "never", "already", "yet"]', 0, 'ever/never/already/yet: "Ever" in questions = at any point in your life. "Have you ever tried..." = lifetime experience question.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'They have _____ arrived.', '["ever", "never", "already", "yet"]', 2, 'ever/never/already/yet: "Already" = arrived earlier than expected. Shows completion before anticipated time.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'I have _____ failed an exam.', '["ever", "never", "already", "yet"]', 1, 'ever/never/already/yet: "Never" = not even once. "I have never failed" = no failures in lifetime.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'Has she called you _____?', '["ever", "never", "already", "yet"]', 3, 'ever/never/already/yet: "Yet" in questions = by now. "Has she called yet?" = asking if she called by this time.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'We have _____ completed the project.', '["ever", "never", "already", "yet"]', 2, 'ever/never/already/yet: "Already" = finished earlier than expected. Shows early completion.', 'easy'),

-- MEDIUM (10 questions)
('foundation', 'present-perfect', 'intermediate', 'Where does "already" go? She _____ has _____ finished _____ her work.', '["Position 1", "Position 2 (between has and finished)", "Position 3 (after finished)", "Any position"]', 1, 'ever/never/already/yet: "Already" goes BETWEEN have/has and V3. Correct: "She has already finished." Position: have/has + already + V3.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Where does "yet" go? Have _____ you _____ finished _____ your work _____?', '["Position 1", "Position 2", "Position 3", "Position 4 (at end)"]', 3, 'ever/never/already/yet: "Yet" goes at THE END in questions. Correct: "Have you finished your work yet?" Always at end.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'What is wrong? "I have yet not finished."', '["Say I haven''t finished yet", "Say I have finished not yet", "Say I yet have not finished", "Nothing wrong"]', 0, 'ever/never/already/yet: "Yet" goes at END (not between words). Correct: "I haven''t finished yet." Pattern: haven''t + V3 + yet.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Choose the natural question:', '["Have you ever to Delhi been?", "Have you been ever to Delhi?", "Have you ever been to Delhi?", "Ever have you been to Delhi?"]', 2, 'ever/never/already/yet: "Ever" goes AFTER have/has. Correct: "Have you ever been to Delhi?" Pattern: Have + you + ever + V3.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Arrange correctly: never / have / I / such / seen / thing / a', '["I have never seen such a thing", "I never have seen such a thing", "Never I have seen such a thing", "I have seen never such a thing"]', 0, 'ever/never/already/yet: "Never" goes BETWEEN have and V3. Order: I + have + never + seen. Pattern: have + never + V3.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'What is the difference? A) "I haven''t finished yet." B) "I have already finished."', '["A = not complete, B = complete", "A = complete, B = not complete", "Both mean the same", "Both are wrong"]', 0, 'ever/never/already/yet: "Haven''t...yet" = still not done. "Have already" = done early. Opposite meanings!', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Choose the correct sentence:', '["She has yet finished her work.", "She has finished already her work.", "She has already finished her work.", "She has her work already finished."]', 2, 'ever/never/already/yet: "Already" goes between has and V3. Correct: "She has already finished her work." Pattern: has + already + V3.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Responding to "Have you eaten?" when you just ate:', '["Yes, I have eaten already.", "Yes, I have already eaten.", "Yes, I already have eaten.", "All are correct"]', 1, 'ever/never/already/yet: "Already" between have and V3 is most natural. "I have already eaten" = common response.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'What is wrong? "I have finished already."', '["Put already before finished", "Put already after have", "Put already at the beginning", "Nothing wrong"]', 3, 'ever/never/already/yet: "Already" can go BEFORE V3 or AT END. Both correct! "I have already finished" or "I have finished already."', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Rearrange: yet / finished / you / Have / homework / your', '["Have you finished your homework yet", "Have you yet finished your homework", "Yet have you finished your homework", "Have yet you finished your homework"]', 0, 'ever/never/already/yet: "Yet" at end in questions. Order: Have + you + finished + your homework + yet. Natural question structure.', 'medium'),

-- HARD (4 questions)
('foundation', 'present-perfect', 'intermediate', 'Which is most natural in spoken English?', '["I already have finished.", "I have finished already.", "I have already finished.", "Already I have finished."]', 2, 'ever/never/already/yet: "Have + already + V3" is most natural in conversation. "I have already finished" = common spoken form.', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'Find the subtle difference: A) "I haven''t called her yet." B) "I still haven''t called her."', '["A = neutral, B = emphasizes delay", "A = emphasizes delay, B = neutral", "Both mean exactly the same", "B is grammatically wrong"]', 0, 'ever/never/already/yet: "Yet" = neutral statement. "Still" = emphasizes surprise/frustration about delay. B shows stronger emotion!', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'Which is correct? "This is the best movie I have _____ seen."', '["ever", "never", "already", "yet"]', 0, 'ever/never/already/yet: "Ever" with superlatives. "The best...I have ever seen" = best in my lifetime. Pattern: superlative + ever.', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'Arrange correctly: met / Have / ever / famous / a / person / you', '["Have you ever met a famous person", "Have ever you met a famous person", "Ever have you met a famous person", "Have you met ever a famous person"]', 0, 'ever/never/already/yet: Question order: Have + you + ever + V3 + object. Natural: "Have you ever met a famous person?" Ever goes after subject.', 'hard'),

-- ============================================================================
-- SUBTOPIC 4: since vs for (duration) - 24 questions
-- ============================================================================

-- EASY (10 questions)
('foundation', 'present-perfect', 'intermediate', 'I have lived here _____ 5 years.', '["since", "for", "from", "during"]', 1, 'since vs for: "For" + period of time (5 years, 2 months, 3 days). Shows duration/length of time.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'She has worked here _____ 2020.', '["since", "for", "from", "during"]', 0, 'since vs for: "Since" + specific starting point (2020, Monday, January). Shows when it started.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'They have been married _____ 10 years.', '["since", "for", "from", "during"]', 1, 'since vs for: "For" + number + time unit (10 years). Period of time = use "for".', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'He has been ill _____ last week.', '["since", "for", "from", "during"]', 0, 'since vs for: "Since" + last week (specific point). Starting point in past = "since".', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'We have known each other _____ 2018.', '["since", "for", "from", "during"]', 0, 'since vs for: "Since" + year (2018). Specific starting year = "since".', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'I haven''t seen him _____ a long time.', '["since", "for", "from", "during"]', 1, 'since vs for: "For" + a long time (period/duration). Length of time = "for".', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'She has lived in Mumbai _____ her childhood.', '["since", "for", "from", "during"]', 0, 'since vs for: "Since" + childhood (starting point in past). When it began = "since".', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'They have been waiting _____ two hours.', '["since", "for", "from", "during"]', 1, 'since vs for: "For" + two hours (duration). Period of time = "for".', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'I have been learning English _____ six months.', '["since", "for", "from", "during"]', 1, 'since vs for: "For" + six months (duration). How long = "for".', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'He hasn''t eaten _____ morning.', '["since", "for", "from", "during"]', 0, 'since vs for: "Since" + morning (starting point). When he last ate = "since".', 'easy'),

-- MEDIUM (10 questions)
('foundation', 'present-perfect', 'intermediate', 'What is wrong? "I have lived here since 5 years."', '["Use for instead of since", "Use from instead of since", "Use during instead of since", "Nothing wrong"]', 0, 'since vs for: "5 years" = period/duration = use "for" (not "since"). Correct: "I have lived here for 5 years." Since = point, for = period.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Choose the correct sentence:', '["She has worked here for January.", "She has worked here since January.", "She has worked here from January.", "She has worked here during January."]', 1, 'since vs for: "January" = specific month = starting point = "since". Correct: "Since January."', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Complete: I haven''t seen her _____ last Monday.', '["since", "for", "from", "during"]', 0, 'since vs for: "Last Monday" = specific day = starting point. Use "since" with days/dates.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'What is the error? "They have been friends for they were children."', '["Use since instead of for", "Use from instead of for", "Use during instead of for", "Nothing wrong"]', 0, 'since vs for: "They were children" = point in time/event = "since". Correct: "Since they were children." For = period (3 years), since = point (2020, childhood).', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Arrange correctly: years / lived / have / here / for / We / ten', '["We have lived here for ten years", "We have lived for ten years here", "For ten years we have lived here", "We have for ten years lived here"]', 0, 'since vs for: Pattern: Subject + have + V3 + place + for + duration. Order: We have lived here for ten years. Natural word order.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Choose which needs "since":', '["... 3 months", "... last year", "... a long time", "... many years"]', 1, 'since vs for: "Last year" = specific point = "since". Others are periods: 3 months, a long time, many years = "for".', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Talking about your job at an interview:', '["I work here for 2 years.", "I worked here for 2 years.", "I have worked here for 2 years.", "I am working here for 2 years."]', 2, 'since vs for: Ongoing from past to present = present perfect + for. "I have worked here for 2 years" = still working here.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'What is wrong? "She hasn''t called since 3 days."', '["Use for instead of since", "Use from instead of since", "Use during instead of since", "Nothing wrong"]', 0, 'since vs for: "3 days" = period = "for" (not "since"). Correct: "She hasn''t called for 3 days." Since = point, for = period.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Rearrange: morning / seen / have / I / him / this / since / not', '["I have not seen him since this morning", "I have not seen since this morning him", "Since this morning I have not seen him", "I have since this morning not seen him"]', 0, 'since vs for: Pattern: Subject + have + not + V3 + object + since + point. Natural: I have not seen him since this morning.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Choose the correct time expression:', '["I have known her since ages.", "I have known her for ages.", "I have known her from ages.", "I have known her during ages."]', 1, 'since vs for: "Ages" = long period = "for". Correct: "For ages" = for a very long time. Since = point, for = period.', 'medium'),

-- HARD (4 questions)
('foundation', 'present-perfect', 'intermediate', 'Which is grammatically perfect?', '["I have been waiting since 2 hours.", "I have been waiting for 2 hours.", "I have been waiting from 2 hours.", "I have been waiting during 2 hours."]', 1, 'since vs for: "2 hours" = duration/period = "for" (not "since"). Correct: "I have been waiting for 2 hours."', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'Find the error: "We have been living here since many years."', '["Use for instead of since", "Use from instead of since", "Use during instead of since", "No error"]', 0, 'since vs for: "Many years" = period = "for". Correct: "We have been living here for many years." Since = point (2020, Monday), for = period (many years).', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'Arrange correctly: the / started / company / since / worked / here / has / He', '["He has worked here since the company started", "He has since the company started worked here", "Since the company started he has worked here", "He has worked since the company started here"]', 0, 'since vs for: Pattern: Subject + have + V3 + place + since + [clause]. Order: He has worked here since the company started. Since + event/action.', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'Which is most natural in formal writing?', '["I have been employed here for the past 5 years.", "I have been employed here since 5 years.", "I have been employed here during 5 years.", "I am employed here for 5 years."]', 0, 'since vs for: "For the past 5 years" = formal professional expression. Most formal: present perfect + for + the past + period.', 'hard'),

