-- SUBTOPIC 5: Perfect vs Simple Past (when to use each) - 24 questions
-- ============================================================================

-- EASY (10 questions)
('foundation', 'present-perfect', 'intermediate', 'Which shows a completed past action with NO connection to now? A) I have eaten. B) I ate.', '["A (Present Perfect)", "B (Simple Past)", "Both mean the same", "Neither is correct"]', 1, 'Perfect vs Simple Past: Simple past = finished action, no connection to present. Present perfect = past action affecting now.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'I _____ to Delhi last year. (specific time in past)', '["have been", "was", "went", "have gone"]', 2, 'Perfect vs Simple Past: "Last year" = specific finished time = simple past. Use "went" (not "have been"). Specific time = simple past.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'I _____ this movie many times. (lifetime experience)', '["saw", "have seen", "see", "am seeing"]', 1, 'Perfect vs Simple Past: Lifetime experience (no specific time) = present perfect. "I have seen" = multiple times in my life.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'She _____ her keys yesterday. (specific time)', '["has lost", "lost", "loses", "is losing"]', 1, 'Perfect vs Simple Past: "Yesterday" = specific time = simple past. Use "lost" (not "has lost"). Yesterday/last week/2020 = simple past.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'We _____ here for 5 years. (still living here)', '["lived", "have lived", "live", "are living"]', 1, 'Perfect vs Simple Past: Ongoing from past to present = present perfect. "Have lived" = still living here now.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'He _____ that movie last night. (finished time)', '["has watched", "watched", "watches", "is watching"]', 1, 'Perfect vs Simple Past: "Last night" = specific finished time = simple past. Use "watched".', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'I _____ never _____ this before. (lifetime experience)', '["did / see", "have / seen", "do / see", "am / seeing"]', 1, 'Perfect vs Simple Past: "Never" with lifetime = present perfect. "I have never seen" = no experience in my life.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'They _____ the project two days ago. (specific time)', '["have completed", "completed", "complete", "are completing"]', 1, 'Perfect vs Simple Past: "Two days ago" = specific time = simple past. Use "completed".', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'She _____ sick recently. (recent time, still relevant)', '["was", "has been", "is", "is being"]', 1, 'Perfect vs Simple Past: "Recently" with ongoing/repeated = present perfect. "Has been" = recent experiences affecting now.', 'easy'),

('foundation', 'present-perfect', 'intermediate', 'I _____ him at the party. (specific event in past)', '["have met", "met", "meet", "am meeting"]', 1, 'Perfect vs Simple Past: "At the party" = specific past event = simple past. Use "met".', 'easy'),

-- MEDIUM (10 questions)
('foundation', 'present-perfect', 'intermediate', 'What''s the difference? A) "I lost my keys." B) "I have lost my keys."', '["A = found them, B = still lost", "A = still lost, B = found them", "Both mean the same", "Both are wrong"]', 0, 'Perfect vs Simple Past: A = past action (maybe found now). B = past action with present result (still don''t have them). Present perfect emphasizes current state!', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Choose the correct sentence for a resume:', '["I worked in IT from 2018 to 2023.", "I have worked in IT from 2018 to 2023.", "I work in IT from 2018 to 2023.", "I am working in IT from 2018 to 2023."]', 0, 'Perfect vs Simple Past: Finished job period = simple past. "I worked from...to..." = no longer working there. If still working, use present perfect.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Reporting recent news:', '["The Prime Minister visited the USA.", "The Prime Minister has visited the USA.", "Both are correct", "Neither is correct"]', 2, 'Perfect vs Simple Past: Both correct! Depends on perspective. A = emphasizes when (specific past). B = emphasizes current relevance. News can use either!', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'What is wrong? "I have seen that movie last week."', '["Use saw instead of have seen", "Remove last week", "Use had seen instead", "Nothing wrong"]', 0, 'Perfect vs Simple Past: "Last week" = specific time = can''t use present perfect. Correct: "I saw that movie last week." Specific time = simple past only.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Talking about someone who died:', '["Shakespeare wrote many plays.", "Shakespeare has written many plays.", "Both mean the same", "Neither is correct"]', 0, 'Perfect vs Simple Past: Dead person = simple past only. "Shakespeare wrote" (not "has written"). Dead = finished life = can''t use present perfect.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Choose the natural sentence:', '["Have you been to Delhi? - Yes, I went last year.", "Have you been to Delhi? - Yes, I have been last year.", "Did you go to Delhi? - Yes, I have been.", "Both A and C are natural"]', 0, 'Perfect vs Simple Past: Question in perfect, answer can be simple past (with time). "Have you been?" (lifetime) - "Yes, I went last year" (specific time). Natural conversation!', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Arrange correctly: this / eaten / at / I / restaurant / before / have', '["I have eaten at this restaurant before", "I have eaten before at this restaurant", "At this restaurant I have eaten before", "I have before eaten at this restaurant"]', 0, 'Perfect vs Simple Past: Pattern: I + have + V3 + at + place + before. "Before" = sometime in past (not specific when) = present perfect.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'What is the error? "I have graduated in 2020."', '["Use graduated instead of have graduated", "Remove in 2020", "Use had graduated", "Nothing wrong"]', 0, 'Perfect vs Simple Past: "In 2020" = specific year = simple past. Correct: "I graduated in 2020." Can''t mix present perfect + specific time.', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Talking about a living author:', '["J.K. Rowling wrote 7 Harry Potter books.", "J.K. Rowling has written 7 Harry Potter books.", "Both are correct", "Neither is correct"]', 2, 'Perfect vs Simple Past: Living person = both work! A = focuses on past completion. B = emphasizes achievements relevant to present. Both grammatically correct!', 'medium'),

('foundation', 'present-perfect', 'intermediate', 'Choose the formal business sentence:', '["We completed the project.", "We have completed the project.", "We had completed the project.", "We will complete the project."]', 1, 'Perfect vs Simple Past: Present perfect is more formal/polite. "We have completed" = emphasizes current status (ready now). More professional than simple past.', 'medium'),

-- HARD (4 questions)
('foundation', 'present-perfect', 'intermediate', 'Which is correct? "This is the first time I _____ sushi."', '["ate", "have eaten", "eat", "am eating"]', 1, 'Perfect vs Simple Past: "This is the first time..." = lifetime experience = present perfect. Always: "This is the first/second/best time I have + V3."', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'Find the subtle meaning: A) "I lived in Mumbai." B) "I have lived in Mumbai."', '["A = don''t live there now, B = still live there OR lived and it''s relevant", "A = still live there, B = don''t live there now", "Both mean the same", "Both are wrong"]', 0, 'Perfect vs Simple Past: A = simple past = finished (don''t live there anymore). B = present perfect = still living there OR past experience relevant to now. Context matters!', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'Arrange correctly: times / visited / He / India / has / three', '["He has visited India three times", "He has three times visited India", "Three times he has visited India", "He has visited three times India"]', 0, 'Perfect vs Simple Past: Pattern: He + has + V3 + place + frequency. Frequency goes at end. Unspecified times = present perfect.', 'hard'),

('foundation', 'present-perfect', 'intermediate', 'What is wrong? "When have you graduated from college?"', '["Use did instead of have", "Use do instead of have", "Use are instead of have", "Nothing wrong"]', 0, 'Perfect vs Simple Past: "When" asks for specific time = can''t use present perfect. Correct: "When did you graduate?" Questions with when/what time = simple past only.', 'hard');

